  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n//////////////////////////////////////////////////////\n// ENUMS\n//////////////////////////////////////////////////////\n\nenum Role {\n  SUPER_ADMIN\n  ADMIN\n  MANAGER\n  EMPLOYEE\n}\n\nenum Designation {\n  INTERN\n  SOFTWARE_ENGINEER\n  SENIOR_ENGINEER\n  TECH_LEAD\n  MANAGER\n  HR\n  DIRECTOR\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  HALF_DAY\n  LEAVE\n}\n\nenum LeaveType {\n  CASUAL\n  SICK\n  EARNED\n  UNPAID\n}\n\nenum LeaveStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum DepartmentType {\n  IT\n  SALES\n  HR\n  FINANCE\n  MARKETING\n  OPERATIONS\n}\n\nenum Status {\n  PENDING\n  ACTIVE\n  INACTIVE\n}\n\n//////////////////////////////////////////////////////\n// PERMISSIONS\n//////////////////////////////////////////////////////\n\nmodel Permission {\n  id          Int     @id @default(autoincrement())\n  code        String  @unique // e.g., USERS:CREATE\n  description String?\n\n  roles     RolePermission[]\n  createdAt DateTime         @default(now())\n  updatedAt DateTime         @updatedAt\n}\n\nmodel RolePermission {\n  id           Int        @id @default(autoincrement())\n  role         Role\n  permissionId Int\n  permission   Permission @relation(fields: [permissionId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([role, permissionId])\n}\n\n//////////////////////////////////////////////////////\n// COMPANY\n//////////////////////////////////////////////////////\n\nmodel Company {\n  id       Int     @id @default(autoincrement())\n  name     String\n  code     String  @unique\n  isActive Boolean @default(true)\n\n  users       User[]\n  departments Department[]\n  attendances Attendance[]\n  projects    Project[]\n  employees   Employee[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n//////////////////////////////////////////////////////\n// USER (AUTH ONLY)\n//////////////////////////////////////////////////////\n\nmodel User {\n  id          Int     @id @default(autoincrement())\n  email       String  @unique\n  firstName   String\n  lastName    String\n  phone       String\n  designation String\n  role        Role\n  status      Status  @default(PENDING)\n  password    String?\n  isActive    Boolean @default(false)\n\n  inviteToken  String?   @unique\n  inviteExpiry DateTime?\n  tempPassword String?\n  otp          String?\n  otpExpiry    DateTime?\n\n  resetOtp       String?\n  resetOtpExpiry DateTime?\n\n  passwordResetAllowed Boolean @default(false) // ✅ ADD THIS\n\n  companyId Int?\n  company   Company? @relation(fields: [companyId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  employee Employee?\n}\n\n//////////////////////////////////////////////////////\n// DEPARTMENT\n//////////////////////////////////////////////////////\n\nmodel Department {\n  id   Int            @id @default(autoincrement())\n  name String\n  type DepartmentType\n\n  companyId Int\n  company   Company @relation(fields: [companyId], references: [id])\n\n  managerId Int?      @unique\n  manager   Employee? @relation(\"DepartmentManager\", fields: [managerId], references: [id])\n\n  employees Employee[] @relation(\"DepartmentEmployees\")\n\n  projects    Project[]\n  attendances Attendance[]\n  leaves      Leave[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([companyId, name])\n}\n\n//////////////////////////////////////////////////////\n// EMPLOYEE (REAL PERSON)\n//////////////////////////////////////////////////////\n\nmodel Employee {\n  id           Int @id @default(autoincrement())\n  userId       Int @unique\n  companyId    Int\n  departmentId Int\n\n  user       User       @relation(fields: [userId], references: [id])\n  company    Company    @relation(fields: [companyId], references: [id])\n  department Department @relation(\"DepartmentEmployees\", fields: [departmentId], references: [id])\n\n  name         String\n  designation  Designation\n  employeeCode String      @unique\n\n  managerId    Int?\n  manager      Employee?  @relation(\"ReportingManager\", fields: [managerId], references: [id], onDelete: NoAction, onUpdate: NoAction)\n  subordinates Employee[] @relation(\"ReportingManager\")\n\n  managedDepartment Department? @relation(\"DepartmentManager\")\n\n  attendances    Attendance[]\n  leaves         Leave[]\n  approvedLeaves Leave[]      @relation(\"LeaveApprover\")\n\n  ownedProjects  Project[] @relation(\"ProjectOwner\")\n  memberProjects Project[] @relation(\"ProjectMembers\")\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n//////////////////////////////////////////////////////\n// ATTENDANCE\n//////////////////////////////////////////////////////\n\nmodel Attendance {\n  id Int @id @default(autoincrement())\n\n  employeeId Int\n  employee   Employee @relation(fields: [employeeId], references: [id])\n\n  companyId Int\n  company   Company @relation(fields: [companyId], references: [id])\n\n  departmentId Int\n  department   Department @relation(fields: [departmentId], references: [id])\n\n  date     DateTime\n  status   AttendanceStatus\n  checkIn  DateTime?\n  checkOut DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([employeeId, date])\n}\n\n//////////////////////////////////////////////////////\n// LEAVE\n//////////////////////////////////////////////////////\n\nmodel Leave {\n  id Int @id @default(autoincrement())\n\n  employeeId Int\n  employee   Employee @relation(fields: [employeeId], references: [id])\n\n  departmentId Int\n  department   Department @relation(fields: [departmentId], references: [id])\n\n  type   LeaveType\n  status LeaveStatus @default(PENDING)\n  reason String?\n\n  startDate DateTime\n  endDate   DateTime\n\n  approvedById Int?\n  approvedBy   Employee? @relation(\"LeaveApprover\", fields: [approvedById], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n//////////////////////////////////////////////////////\n// PROJECT\n//////////////////////////////////////////////////////\n\nmodel Project {\n  id          Int     @id @default(autoincrement())\n  name        String\n  description String?\n\n  companyId Int\n  company   Company @relation(fields: [companyId], references: [id])\n\n  departmentId Int\n  department   Department @relation(fields: [departmentId], references: [id])\n\n  ownerId Int\n  owner   Employee @relation(\"ProjectOwner\", fields: [ownerId], references: [id])\n\n  members Employee[] @relation(\"ProjectMembers\")\n\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
